// Summarise the Website Chat Log for Echo / the BFC Team.
const rows = $input.all().map(i => i.json);
const norm = s => String(s || '').toLowerCase().trim();

const focus = norm($('When Executed by Another Workflow').first().json.focus) || 'all';

const isLead    = r => norm(r['Bot Status']) === 'trial_requested' || norm(r['Is Lead']) === 'yes';
const isIssue   = r => norm(r['Bot Status']) === 'issue_detected';
const isUnknown = r => norm(r['Bot Status']) === 'unknown_question';
const isOpen    = r => !['done', 'closed', 'resolved'].includes(norm(r['Status']));

const mapRow = r => ({
  date: r['Date / Time'] || '',
  conversation_id: r['Conversation ID'] || '',
  name: r['Visitor Name'] || '',
  email: r['Email'] || '',
  phone: r['Phone'] || '',
  topic: r['Enquiry Topic'] || '',
  summary: r['Enquiry Summary'] || '',
  is_lead: r['Is Lead'] || '',
  urgency: r['Urgency'] || '',
  next_action: r['Recommended Next Action'] || '',
  bot_status: r['Bot Status'] || '',
  status: r['Status'] || '',
  page_url: r['Page URL'] || ''
});

const leads   = rows.filter(isLead);
const issues  = rows.filter(isIssue);
const unknown = rows.filter(isUnknown);
const open    = rows.filter(isOpen);
const recent  = rows.slice(-15).reverse();

const out = {
  success: true,
  message: 'Website chat log review completed.',
  focus,
  total_chats_logged: rows.length,
  lead_count: leads.length,
  issue_count: issues.length,
  unknown_question_count: unknown.length,
  open_items_count: open.length
};

if (focus === 'leads')               out.leads = leads.map(mapRow);
else if (focus === 'issues')         out.issues = issues.map(mapRow);
else if (focus === 'unknown_questions') out.unknown_questions = unknown.map(r => ({ question: r['Enquiry Summary'] || r['Enquiry Topic'] || '', date: r['Date / Time'] || '' }));
else {
  out.leads = leads.map(mapRow);
  out.issues = issues.map(mapRow);
  out.unknown_questions = unknown.map(r => ({ question: r['Enquiry Summary'] || r['Enquiry Topic'] || '', date: r['Date / Time'] || '' }));
  out.recent = recent.map(mapRow);
}

return [{ json: out }];
